from collections import deque


class _N:
    __slots__ = ("val", "left", "right")
    def __init__(self, v): self.val = v; self.left = None; self.right = None


def _build(vals):
    if not vals or vals[0] is None: return None
    root = _N(vals[0]); q = deque([root]); i = 1
    while q and i < len(vals):
        n = q.popleft()
        if i < len(vals):
            if vals[i] is not None: n.left = _N(vals[i]); q.append(n.left)
            i += 1
        if i < len(vals):
            if vals[i] is not None: n.right = _N(vals[i]); q.append(n.right)
            i += 1
    return root


def _serialize(root):
    if not root: return []
    out = []; q = deque([root])
    while q:
        n = q.popleft()
        if n is None: out.append(None); continue
        out.append(n.val); q.append(n.left); q.append(n.right)
    while out and out[-1] is None: out.pop()
    return out


def codec(vals):
    def encode(node):
        if node is None:
            return "#"
        return f"{node.val},{encode(node.left)},{encode(node.right)}"

    def decode(data):
        tokens = iter(data.split(","))

        def build():
            tok = next(tokens)
            if tok == "#":
                return None
            node = _N(int(tok))
            node.left = build()
            node.right = build()
            return node

        return build()

    tree = _build(vals)
    encoded = encode(tree)
    rebuilt = decode(encoded)
    return _serialize(rebuilt)
